import React, { useState, useEffect, useLayoutEffect, useCallback } from 'react';
import { GameState, ClanMember, Region, Realm, Building, Inventory, GameEvent, TaskType, MysticRealm } from './types';
import { INITIAL_MEMBERS, INITIAL_REGIONS, REALM_ORDER, BUILDING_TYPES, ALL_ITEM_DETAILS, RECIPES, CULTIVATION_SLOT_BONUSES, VEIN_LEVELS } from './constants';
import { CLAN_MASTER_REGISTRY } from './data/master_registry';
import { CharacterController } from './services/CharacterController';
import { EventController } from './services/EventController';
import { OracleService } from './services/OracleService';
import ClanDashboard from './components/MembersPanel/ClanDashboard';
import WorldMap from './components/Map/WorldMap';
import ClanManagement from './components/ClanManagement/ClanManagement';
import BreakthroughModal from './components/Xiulian/BreakthroughModal';
import EventModal from './components/events/EventModal';
import RegionInfoPanel from './components/Map/RegionInfoPanel';

const SEASON_NAMES = ['', '春', '夏', '秋', '冬'];

const App: React.FC = () => {
    const [state, setState] = useState<GameState>(() => {
        const initializedMembers = INITIAL_MEMBERS.map(m => ({
            ...m,
            rootGrade: CharacterController.getAutoRootGrade(m.roots)
        })) as ClanMember[];

        return {
            year: 1,
            season: 1,
            spiritStones: CLAN_MASTER_REGISTRY.spiritStones,
            merit: CLAN_MASTER_REGISTRY.merit,
            luck: CLAN_MASTER_REGISTRY.luck,
            members: initializedMembers,
            regions: INITIAL_REGIONS,
            buildings: [],
            inventory: CLAN_MASTER_REGISTRY.inventory,
            currentRegionId: '',
            logs: ["太平历初，望月李氏在此立基。"],
            heritagePool: CLAN_MASTER_REGISTRY.heritagePool,
            unlockedPositions: ['家主', '弟子'],
            flags: {},
            eventQueue: [],
            factionReputation: { '魏家': 50, '邵家': 50, '北寒宗': 50 },
            activeMysticRealms: []
        };
    });

    const [pendingEvents, setPendingEvents] = useState<GameEvent[]>([]);
    const [isProcessing, setIsProcessing] = useState(false);
    const [isDashboardVisible, setIsDashboardVisible] = useState(true);
    const [isManagementVisible, setIsManagementVisible] = useState(false);
    const [isConsoleCollapsed, setIsConsoleCollapsed] = useState(false);
    const [breakingMemberId, setBreakingMemberId] = useState<string | null>(null);
    const [isMapOverview, setIsMapOverview] = useState(false);

    const [scale, setScale] = useState(1);

    const updateScale = useCallback(() => {
        const ww = window.innerWidth;
        const wh = window.innerHeight;
        const targetW = 1920;
        const targetH = 1080;
        const scaleW = ww / targetW;
        const scaleH = wh / targetH;
        const newScale = Math.min(scaleW, scaleH);
        setScale(Math.max(newScale, 0.1));
    }, []);

    useLayoutEffect(() => {
        updateScale();
        window.addEventListener('resize', updateScale);
        return () => window.removeEventListener('resize', updateScale);
    }, [updateScale]);

    useEffect(() => {
        if (state.season === 1) {
            const oracle = OracleService.getYearlyOracle(state);
            setState(prev => ({
                ...prev,
                logs: [`【昊天镜】老祖谕令：${oracle}`, ...prev.logs].slice(0, 40)
            }));
        }
    }, [state.year, state.season]);

    const handleUpdateMember = (id: string, updates: Partial<ClanMember>) => {
        setState(prev => {
            const member = prev.members.find(m => m.id === id);
            if (!member) return prev;
            const { updatedMember, logs } = CharacterController.updateMember(member, updates, prev.year);
            let updatedMembers = prev.members.map(m => m.id === id ? updatedMember : m);
            if (updates.position === '家主') {
                updatedMembers = updatedMembers.map(m => 
                    (m.position === '家主' && m.id !== id) ? { ...m, position: '弟子' } : m
                );
            }
            return {
                ...prev,
                members: updatedMembers,
                logs: logs.length > 0 ? [...logs, ...prev.logs].slice(0, 30) : prev.logs
            };
        });
    };

    const handleAssignMission = (targetIds: string | string[], missionType: string) => {
        const regionId = state.currentRegionId;
        if (!regionId) return;
        const ids = Array.isArray(targetIds) ? targetIds : [targetIds];

        setState(prev => {
            const region = prev.regions.find(r => r.id === regionId);
            if (!region) return prev;

            const updatedMembers = prev.members.map(m => 
                ids.includes(m.id) ? { 
                    ...m, 
                    assignment: (missionType === 'Guard' || missionType === 'Occupy') ? 'Defending' : 'Mission' as TaskType 
                } : m
            );

            const updatedRegions = prev.regions.map(r => 
                r.id === regionId ? {
                    ...r,
                    owner: (missionType === 'Occupy') ? '望月李氏' as any : r.owner,
                    guardMemberId: (missionType === 'Guard' || missionType === 'Occupy') ? ids[0] : r.guardMemberId,
                    activeMission: (missionType === 'Explore' || missionType === 'Mystic') ? {
                        memberIds: ids,
                        turnsRemaining: missionType === 'Explore' ? 2 : 4,
                        totalTurns: missionType === 'Explore' ? 2 : 4,
                        type: missionType
                    } : undefined
                } : r
            );

            const names = ids.map(id => prev.members.find(m => m.id === id)?.name).join('、');
            return {
                ...prev,
                members: updatedMembers,
                regions: updatedRegions,
                currentRegionId: '',
                logs: [`【派遣】${names} 奉诏前往 ${region.name} 执行 ${missionType} 任务。`, ...prev.logs].slice(0, 30)
            };
        });
    };

    const handleWithdrawGuard = (regionId: string) => {
        setState(prev => {
            const region = prev.regions.find(r => r.id === regionId);
            if (!region || !region.guardMemberId) return prev;

            const updatedMembers = prev.members.map(m => 
                m.id === region.guardMemberId ? { ...m, assignment: 'Idle' as TaskType } : m
            );

            const updatedRegions = prev.regions.map(r => 
                r.id === regionId ? { ...r, guardMemberId: undefined } : r
            );

            return {
                ...prev,
                members: updatedMembers,
                regions: updatedRegions,
                logs: [`【归返】驻守 ${region.name} 的族人已奉命撤回。`, ...prev.logs].slice(0, 30)
            };
        });
    };

    const handleNextTurn = async () => {
        setIsProcessing(true);
        await new Promise(resolve => setTimeout(resolve, 800));
        try {
            let turnLogs: string[] = [];
            let newEvents: GameEvent[] = [];
            let finalInventory = { ...state.inventory };
            let finalSpiritStones = state.spiritStones;
            let finalMerit = state.merit;
            const currentYear = state.year;
            const currentSeason = state.season;
            const nextSeason = currentSeason >= 4 ? 1 : currentSeason + 1;
            const isYearIncrement = currentSeason === 4;

            // 1. Buildings Logic
            const updatedBuildings = state.buildings.map(b => {
                if (!b.isFinished) {
                    const rem = b.turnsRemaining - 1;
                    if (rem <= 0) {
                        turnLogs.push(`【${currentYear}载·营造】${BUILDING_TYPES[b.type].name} 完工入驻。`);
                        return { ...b, isFinished: true, turnsRemaining: 0 };
                    }
                    return { ...b, turnsRemaining: rem };
                }
                if (b.activeProduction) {
                    const rem = b.activeProduction.turnsRemaining - 1;
                    if (rem <= 0) {
                        const recipe = [...RECIPES.Alchemy, ...RECIPES.Smithing].find(r => r.id === b.activeProduction!.recipeId);
                        if (recipe) {
                            const productDetail = ALL_ITEM_DETAILS[recipe.productId] as any;
                            const catKey = productDetail.category === 'pill' ? 'pills' : 'weapons';
                            finalInventory[catKey][recipe.productId] = (finalInventory[catKey][recipe.productId] || 0) + 1;
                            turnLogs.push(`【${currentYear}载·成品】${BUILDING_TYPES[b.type].name} 丹/器成，获得 ${productDetail.name}。`);
                        }
                        return { ...b, activeProduction: undefined };
                    }
                    return { ...b, activeProduction: { ...b.activeProduction, turnsRemaining: rem } };
                }
                return b;
            });

            // 2. Resource Production & Missions Logic
            const updatedRegions = state.regions.map(r => {
                let nr = { ...r };
                // Territory Production
                if (nr.owner === '望月李氏' && nr.guardMemberId) {
                    if (nr.production) {
                        if (nr.production.stones) finalSpiritStones += nr.production.stones;
                        if (nr.production.merit) finalMerit += nr.production.merit;
                        if (nr.production.items) {
                            Object.entries(nr.production.items).forEach(([id, qty]) => {
                                const detail = ALL_ITEM_DETAILS[parseInt(id)] as any;
                                const catKey = detail.category === 'herb' ? 'herbs' : (detail.category === 'mineral' ? 'minerals' : 'pills');
                                finalInventory[catKey as keyof Inventory][parseInt(id)] = (finalInventory[catKey as keyof Inventory][parseInt(id)] || 0) + qty;
                            });
                        }
                    }
                }

                if (nr.activeMission) {
                    const rem = nr.activeMission.turnsRemaining - 1;
                    if (rem <= 0) {
                        if (nr.activeMission.memberIds) {
                            const m = state.members.find(mem => mem.id === nr.activeMission!.memberIds![0]);
                            if (m) newEvents.push(EventController.generateMissionResult(m, nr, currentYear));
                        }
                        nr.activeMission = undefined;
                    } else nr.activeMission = { ...nr.activeMission, turnsRemaining: rem };
                }
                return nr;
            });

            // 3. Members Cultivation & Age
            const updatedMembers = state.members.map(m => {
                let { updatedMember, logs } = CharacterController.processTurn(m, currentYear, isYearIncrement, 1.0);
                turnLogs.push(...logs);
                return updatedMember;
            });

            // 4. Random Events
            if (Math.random() > 0.8) {
              const ev = EventController.generateNextEvent({ ...state, members: updatedMembers, regions: updatedRegions, buildings: updatedBuildings, inventory: finalInventory });
              if (ev) newEvents.push(ev);
            }

            setState(prev => ({
                ...prev,
                year: isYearIncrement ? prev.year + 1 : prev.year,
                season: nextSeason,
                members: updatedMembers,
                regions: updatedRegions,
                buildings: updatedBuildings,
                spiritStones: finalSpiritStones,
                merit: finalMerit,
                inventory: finalInventory,
                logs: [...turnLogs, ...prev.logs].slice(0, 40)
            }));
            if (newEvents.length > 0) setPendingEvents(prev => [...prev, ...newEvents]);
        } finally {
            setIsProcessing(false);
        }
    };

    const handleChoice = (choiceKey: 'choiceA' | 'choiceB') => {
        if (pendingEvents.length === 0) return;
        const updates = EventController.processEventChoice(state, pendingEvents[0], choiceKey);
        setState(prev => ({ ...prev, ...updates }));
        setPendingEvents(prev => prev.slice(1));
    };

    const handleBreakthroughAttempt = (memberId: string, success: boolean, usedPillId?: number) => {
        setState(prev => {
            const member = prev.members.find(m => m.id === memberId);
            if (!member) return prev;
            const { updatedMember, log } = CharacterController.breakthrough(member, success, prev.year, usedPillId);
            return {
                ...prev,
                members: prev.members.map(m => m.id === memberId ? updatedMember : m),
                heritagePool: success ? prev.heritagePool + 10 : prev.heritagePool,
                logs: [log, ...prev.logs].slice(0, 30)
            };
        });
        setBreakingMemberId(null);
    };

    const selectedRegion = state.regions.find(r => r.id === state.currentRegionId);

    return (
        <div className="game-canvas" style={{ transform: `scale(${scale})` }}>
            <div className="h-full w-full relative bg-[#0a0f0d] text-text-main overflow-hidden select-none font-sans">

                <div className="absolute inset-0 z-0">
                    <WorldMap 
                        regions={state.regions} 
                        members={state.members} 
                        reputation={state.factionReputation}
                        currentRegionId={state.currentRegionId} 
                        onSelectRegion={(r) => r?.id === 'li_clan_home' ? setIsManagementVisible(true) : setState(p => ({ ...p, currentRegionId: r ? r.id : '' }))} 
                        onUpdateMember={handleUpdateMember} 
                        onUpdateRegion={(id, u) => setState(p => ({ ...p, regions: p.regions.map(r => r.id === id ? { ...r, ...u } : r) }))}
                        onOverviewChange={setIsMapOverview} 
                    />
                </div>

                {selectedRegion && selectedRegion.id !== 'li_clan_home' && (
                    <RegionInfoPanel 
                        region={selectedRegion} 
                        members={state.members}
                        onClose={() => setState(p => ({ ...p, currentRegionId: '' }))} 
                        onAssignMission={handleAssignMission}
                        onWithdrawGuard={handleWithdrawGuard}
                    />
                )}

                <header className={`absolute top-0 left-0 w-full h-28 flex items-start justify-between px-16 z-20 pointer-events-none pt-4 transition-all duration-500 ease-in-out ${isMapOverview ? 'opacity-0 -translate-y-[120%]' : 'opacity-100 translate-y-0'}`}>
                    <div className="flex items-center gap-12 pointer-events-auto bg-[#131c18]/90 backdrop-blur-md px-12 py-4 rounded-xl border border-accent-gold/20 shadow-[0_15px_40px_rgba(0,0,0,0.8)]">
                        <div className="flex flex-col">
                            <h1 className="font-serif text-3xl font-black text-accent-gold tracking-[0.3em] drop-shadow-[0_2px_8px_rgba(201,160,99,0.5)] uppercase">玄鉴仙族</h1>
                            <span className="text-[10px] text-accent-gold/40 tracking-[0.5em] mt-0.5">HANTIAN ERA</span>
                        </div>
                        <div className="flex gap-14 items-center border-l border-white/5 pl-14">
                            <div className="flex flex-col">
                                <span className="text-[10px] uppercase tracking-widest text-text-disabled mb-1">灵石存续</span>
                                <span className="text-2xl font-bold text-accent-gold font-mono">✨ {state.spiritStones.toLocaleString()}</span>
                            </div>
                            <div className="flex flex-col">
                                <span className="text-[10px] uppercase tracking-widest text-text-disabled mb-1">功德造化</span>
                                <span className="text-2xl font-bold text-blue-400 font-mono">💠 {state.merit}</span>
                            </div>
                            <div className="flex flex-col">
                                <span className="text-[10px] uppercase tracking-widest text-text-disabled mb-1">岁时纪元</span>
                                <span className="text-2xl font-bold text-text-main tracking-widest">{state.year}载 · {SEASON_NAMES[state.season]}</span>
                            </div>
                        </div>
                    </div>

                    <div className="flex items-center gap-6 pointer-events-auto bg-[#131c18]/90 backdrop-blur-md px-8 py-5 rounded-xl border border-white/5 shadow-[0_15px_40px_rgba(0,0,0,0.8)]">
                        <button onClick={() => setIsManagementVisible(true)} className="px-8 py-3 bg-bg-main/60 border border-border-soft text-text-muted rounded-sm font-bold hover:border-accent-jade hover:text-accent-jade transition-all flex items-center gap-2 text-base shadow-inner">🏛️ 家族管理</button>
                        <button onClick={() => setIsDashboardVisible(!isDashboardVisible)} className={`px-8 py-3 rounded-sm border transition-all font-bold flex items-center gap-2 text-base ${isDashboardVisible ? 'bg-accent-jade/20 border-accent-jade text-accent-jade' : 'bg-bg-main/60 border-border-soft text-text-disabled'}`}>📜 族谱常青</button>
                        <button onClick={handleNextTurn} disabled={isProcessing || pendingEvents.length > 0} className="bg-accent-jade hover:brightness-110 disabled:opacity-30 text-bg-main px-12 py-3 rounded-sm font-black transition-all shadow-[0_0_30px_rgba(77,124,107,0.5)] text-lg tracking-widest ml-4">{isProcessing ? '推演因果' : '岁时轮转'}</button>
                    </div>
                </header>

                {isDashboardVisible && (
                    <aside className={`absolute top-36 right-12 bottom-12 w-[480px] z-30 pointer-events-auto transition-all duration-500 ease-in-out ${isMapOverview ? 'opacity-0 translate-x-[110%] pointer-events-none' : 'opacity-100 translate-x-0'}`}>
                        <div className="h-full bg-[#131c18]/95 backdrop-blur-xl border border-border-soft/60 shadow-[0_0_80px_rgba(0,0,0,1)] rounded-xl overflow-hidden flex flex-col ring-1 ring-white/5">
                            <ClanDashboard state={state} onUpdateMember={handleUpdateMember} onAddMember={() => {}} onOpenBreakthrough={(id) => setBreakingMemberId(id)} onContributeItem={() => {}} />
                        </div>
                    </aside>
                )}

                <div className={`absolute bottom-12 left-12 transition-all duration-500 z-30 flex flex-col overflow-hidden pointer-events-auto ${isMapOverview ? 'opacity-0 translate-y-[120%] pointer-events-none' : 'opacity-100 translate-y-0'} ${isConsoleCollapsed ? 'w-64 h-16' : 'w-[520px] h-[360px]'}`}>
                    <div className="h-full bg-[#131c18]/90 backdrop-blur-xl border border-border-soft shadow-[0_20px_60px_rgba(0,0,0,0.9)] rounded-xl overflow-hidden flex flex-col ring-1 ring-white/5">
                        <div className="flex justify-between items-center px-8 py-5 border-b border-white/5 bg-bg-main/40 shrink-0 cursor-pointer group hover:bg-bg-panel transition-all" onClick={() => setIsConsoleCollapsed(!isConsoleCollapsed)}>
                            <div className="flex items-center gap-4">
                                <span className="text-xl">📜</span>
                                <span className="font-serif font-bold text-accent-gold/90 group-hover:text-accent-gold transition-colors tracking-[0.4em] text-base">族史摘要</span>
                            </div>
                            <span className={`text-xs text-accent-gold/60 transition-transform duration-500 ${isConsoleCollapsed ? '-rotate-180' : 'rotate-0'}`}>▼</span>
                        </div>
                        {!isConsoleCollapsed && (
                            <div className="flex-1 overflow-y-auto p-8 space-y-6 custom-scrollbar bg-gradient-to-b from-transparent to-black/30">
                                {state.logs.map((log, i) => (
                                    <div key={i} className="flex gap-5 border-b border-white/5 pb-5 animate-fade-in group" style={{animationDelay: `${i*0.05}s`}}>
                                        <span className="text-accent-jade text-xl shrink-0 opacity-40 group-hover:opacity-100 transition-opacity">◈</span>
                                        <p className="font-sans text-[15px] text-text-muted leading-relaxed tracking-wide group-hover:text-text-main transition-colors">{log}</p>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                </div>

                {isManagementVisible && (
                    <div className="fixed inset-0 z-[500]">
                        <ClanManagement state={state} onUpdateMember={handleUpdateMember} onUpdateBuilding={(id, u) => setState(p => ({ ...p, buildings: p.buildings.map(b => b.id === id ? { ...b, ...u } : b) }))} onUpdateInventory={(u) => setState(p => ({ ...p, inventory: { ...p.inventory, ...u } }))} onAddBuilding={(type) => {
                            const id = `building_${Date.now()}`;
                            const cost = BUILDING_TYPES[type].baseCost;
                            if (state.spiritStones < cost) return;
                            const newBuilding: Building = { id, type, level: 1, assignedMemberId: null, isFinished: false, turnsRemaining: BUILDING_TYPES[type].baseTurns };
                            setState(p => ({ ...p, spiritStones: p.spiritStones - cost, buildings: [...p.buildings, newBuilding] }));
                        }} onCancelBuilding={() => {}} onAssignBuilding={(bid, mid, sidx) => {
                            setState(prev => ({
                                ...prev,
                                buildings: prev.buildings.map(b => {
                                    if (b.id !== bid) return b;
                                    if (sidx !== undefined) {
                                        const ids = [...(b.assignedMemberIds || Array(12).fill(null))];
                                        ids[sidx] = mid;
                                        return { ...b, assignedMemberIds: ids };
                                    }
                                    return { ...b, assignedMemberId: mid };
                                })
                            }));
                        }} onAssignItem={() => {}} onClose={() => setIsManagementVisible(false)} />
                    </div>
                )}

                {pendingEvents.length > 0 && <EventModal event={pendingEvents[0]} onChoice={handleChoice} />}
                {breakingMemberId && (
                    <BreakthroughModal member={state.members.find(m => m.id === breakingMemberId)!} onClose={() => setBreakingMemberId(null)} onAttempt={(success, pillId) => handleBreakthroughAttempt(breakingMemberId, success, pillId)} />
                )}
            </div>
        </div>
    );
};

export default App;

import { ClanMember, Realm, RootGrade, TaskType } from '../types';
import { REALM_ORDER } from '../constants';
import { calculateQuarterlyExpGain, getRequiredExp } from '../components/Xiulian/CultivationSystem';

export class CharacterController {
    /**
     * 自动判定并更新灵根等级
     */
    static getAutoRootGrade(roots: ClanMember['roots']): RootGrade {
        const maxRoot = Math.max(roots.gold, roots.wood, roots.water, roots.fire, roots.earth);
        if (maxRoot === 0) return '凡人';
        if (maxRoot <= 2) return '伪灵根';
        if (maxRoot <= 4) return '下品灵根';
        if (maxRoot <= 6) return '中品灵根';
        if (maxRoot <= 8) return '上品灵根';
        return '极品灵根';
    }

    /**
     * 处理修为进度增长，支持跨级升级
     */
    static applyCultivationProgress(member: ClanMember, logs: string[], year: number): ClanMember {
        if (member.realm === Realm.Mortal) return member;

        let nm = { ...member };
        let progress = nm.cultivationProgress;
        let subRealm = nm.subRealm;
        const realmIdx = REALM_ORDER.indexOf(nm.realm);

        let currentReq = getRequiredExp(realmIdx, subRealm);

        // 处理自动连续升级
        while (progress >= currentReq && subRealm < 9) {
            progress -= currentReq;
            subRealm += 1;
            currentReq = getRequiredExp(realmIdx, subRealm);
            logs.push(`【${year}载·晋升】${nm.name} 气息升华，实时突破至 ${nm.realm} ${subRealm}层。`);
        }

        // 处理大圆满瓶颈
        if (subRealm === 9 && progress >= currentReq) {
            progress = currentReq;
            if (member.subRealm < 9 || member.cultivationProgress < currentReq) {
                logs.push(`【${year}载·瓶颈】${nm.name} 触碰天门，已达 ${nm.realm}巅峰之境。`);
            }
        }

        nm.cultivationProgress = progress;
        nm.subRealm = subRealm;
        return nm;
    }

    /**
     * 在世族人的回合逻辑处理
     * @param externalMultiplier 可选：来自建筑槽位的特定加成（默认1.0）
     */
    static processTurn(member: ClanMember, year: number, isYearIncrement: boolean, externalMultiplier: number = 1.0): { updatedMember: ClanMember; logs: string[]; travelTriggered?: boolean } {
        let nm = { ...member };
        let turnLogs: string[] = [];

        if (nm.status === 'dead') return { updatedMember: nm, logs: [] };

        // 1. 寿命增长
        if (isYearIncrement) {
            nm.age += 1;
            if (nm.age >= nm.maxAge) {
                nm.status = 'dead';
                nm.deathYear = year;
                turnLogs.push(`【${year}载·春】${nm.name} 寿元耗尽，溘然长逝。`);
                return { updatedMember: nm, logs: turnLogs };
            }
        }

        // 2. 伤势康复逻辑
        if (nm.status === 'injured') {
            nm.assignment = 'Recovery';
            if (Math.random() > 0.4) {
                nm.status = 'healthy';
                nm.assignment = 'Idle'; 
                turnLogs.push(`【${year}载】${nm.name} 伤势痊愈，重回家族待命。`);
            }
        }

        // 3. 修为增长逻辑
        const hasRoots = Object.values(nm.roots).some(v => v > 0);
        if (hasRoots && nm.realm !== Realm.Mortal) {
            const baseGain = calculateQuarterlyExpGain(nm);
            let taskMultiplier = 0.1;

            switch (nm.assignment) {
                case 'Cultivation': taskMultiplier = 1.0; break;
                case 'Research':
                case 'Alchemy':
                case 'Smithing': taskMultiplier = 0.6; break;
                case 'Mission': taskMultiplier = 0.4; break;
                case 'Defending': taskMultiplier = 0.5; break;
                case 'Recovery': taskMultiplier = 0.2; break;
                case 'Travel':
                case 'Idle': taskMultiplier = 0.1; break;
                default: taskMultiplier = 0.1;
            }

            // 应用任务基础倍率 * 槽位特定倍率
            nm.cultivationProgress += baseGain * taskMultiplier * externalMultiplier;
            nm = this.applyCultivationProgress(nm, turnLogs, year);
        } else if (nm.realm === Realm.Mortal) {
            nm.assignment = 'Idle';
        }

        // 4. 游历触发概率
        const travelTriggered = nm.status === 'healthy' && nm.assignment === 'Cultivation' && Math.random() < 0.05;

        return { updatedMember: nm, logs: turnLogs, travelTriggered };
    }

    /**
     * 处理外部手动更新
     */
    static updateMember(member: ClanMember, updates: Partial<ClanMember>, year: number): { updatedMember: ClanMember; logs: string[] } {
        let nm = { ...member, ...updates };
        let logs: string[] = [];

        if (updates.roots) {
            const newGrade = this.getAutoRootGrade(nm.roots);
            if (nm.rootGrade !== newGrade) {
                logs.push(`【${year}载·造化】${nm.name} 灵根升华，晋升为 ${newGrade}。`);
                nm.rootGrade = newGrade;
            }
        }

        if (updates.cultivationProgress !== undefined) {
            nm = this.applyCultivationProgress(nm, logs, year);
        }

        return { updatedMember: nm, logs };
    }

    /**
     * 执行大境界突破
     */
    static breakthrough(member: ClanMember, success: boolean, year: number, usedPillId?: number): { updatedMember: ClanMember; log: string } {
        let nm = { ...member };

        if (usedPillId) {
            const newPills = { ...nm.personalInventory.pills };
            if (newPills[usedPillId] > 0) {
                newPills[usedPillId]--;
                if (newPills[usedPillId] === 0) delete newPills[usedPillId];
            }
            nm.personalInventory = { ...nm.personalInventory, pills: newPills };
        }

        if (success) {
            const currentIdx = REALM_ORDER.indexOf(nm.realm);
            const nextRealm = REALM_ORDER[currentIdx + 1] || Realm.YuanShen;
            return {
                updatedMember: {
                    ...nm,
                    realm: nextRealm,
                    subRealm: 1,
                    cultivationProgress: 0,
                    maxAge: nm.maxAge + 100,
                    legacyPoints: (nm.legacyPoints || 0) + 10
                },
                log: `【${year}载·突破】${nm.name} 气息贯通天地，成功晋升至 ${nextRealm}。`
            };
        } else {
            return {
                updatedMember: {
                    ...nm,
                    subRealm: 8,
                    cultivationProgress: 0,
                    status: 'injured',
                    assignment: 'Recovery'
                },
                log: `【${year}载·突破】${nm.name} 叩问天门失败，遭灵力反噬，修为跌落。`
            };
        }
    }
}

export enum Realm {
    Mortal = '凡人',
    QiRefinement = '练气',
    FoundationEstablishment = '筑基',
    Zifu = '紫府',
    JinDan = '金丹',
    YuanYing = '元婴',
    YuanShen = '化神'
}

export enum Element {
    Gold = '金',
    Wood = '木',
    Water = '水',
    Fire = '火',
    Earth = '土'
}

export type SettlementType = 'Capital' | 'Minor' | 'Fort' | 'Resource' | 'Landmark';
export type TaskType = 'Cultivation' | 'Research' | 'Idle' | 'Mission' | 'Alchemy' | 'Smithing' | 'Recovery' | 'Travel' | 'Defending';
export type TalentTier = '凡人' | '平庸' | '普通' | '超凡' | '天才' | '绝世' | '绝世天骄';
export type RootGrade = '凡人' | '伪灵根' | '下品灵根' | '中品灵根' | '上品灵根' | '极品灵根';
export type DevelopmentPlan = 'Combat' | 'Alchemy' | 'Smithing' | 'Talisman' | 'Balanced';

export type BuildingCategory = '资源产出' | '家族功能' | '修行基础';
export type RegionType = 'lake' | 'mountain' | 'forest' | 'city' | 'sect' | 'ruins' | 'cave' | 'island' | 'desert' | 'mine' | 'field' | 'volcano' | 'mystic_realm';
export type RegionCategory = 'Stakeholder' | 'Natural' | 'Mystic' | 'Resource';
export type FactionType = '望月李氏' | '北寒宗' | '天一剑宗' | '离火门' | '魏家' | '邵家' | '齐家' | '万花谷' | '无';
export type MethodType = 'Cultivation' | 'Combat' | 'Movement';

/**
 * Interface representing a cultivation method, combat art, or movement technique.
 */
export interface CultivationMethod {
    id: number;
    name: string;
    grade: number;
    quality: string;
    type: MethodType;
    element: Element | '无';
    desc: string;
    bonus: string;
    buffs: Record<string, number>;
    requirements?: {
        realm?: Realm;
        minRootGrade?: RootGrade;
        minRoots?: Record<string, number>;
    };
}

export interface EventChoice {
    text: string;
    effect: string;
    nextEventId?: string;
    flagsSet?: Record<string, boolean | number>;
}

export interface GameEvent {
    id: string;
    title: string;
    content: string;
    choiceA: EventChoice;
    choiceB: EventChoice;
    requirements?: {
        minYear?: number;
        minMerit?: number;
        requiredFlags?: string[];
        forbiddenFlags?: string[];
        minSpiritStones?: number;
    };
    impact: {
        spiritStones?: number;
        merit?: number;
        luck?: number;
        log?: string;
        eventType?: 'standard' | 'travel' | 'plot' | 'mission' | 'mystic';
        memberId?: string;
        memberIds?: string[];
        regionId?: string;
        newOwner?: FactionType;
        reputationChange?: Record<string, number>;
        items?: Record<number, number>; 
    };
}

export interface Building {
    id: string;
    type: string;
    level: number;
    assignedMemberId: string | null;
    assignedMemberIds?: (string | null)[];
    isFinished: boolean;
    turnsRemaining: number;
    activeProduction?: {
        recipeId: number;
        turnsRemaining: number;
        type: 'Alchemy' | 'Smithing';
    };
    veinLevel?: number;
    veinExp?: number;
}

export interface Inventory {
    herbs: Record<number, number>;
    minerals: Record<number, number>;
    paper: number;
    pills: Record<number, number>;
    weapons: Record<number, number>;
    methods: Record<number, number>;
    scrolls: Record<number, number>;
}

export interface SpecializedTalents {
    战斗天赋: {
        剑法: number;
        拳法: number;
        枪法: number;
        刀法: number;
        弓箭: number;
    };
    百艺天赋: {
        炼丹: number;
        炼器: number;
        制符: number;
        阵法: number;
    };
}

export interface ClanMember {
    id: string;
    name: string;
    gender: '男' | '女';
    realm: Realm;
    subRealm: number; 
    age: number;
    maxAge: number;
    physique: string;
    aptitude: number;
    comprehension: number;
    divineSense: number;
    aspiration: string;
    contributionPoints: number;
    roots: {
        gold: number;
        wood: number;
        water: number;
        fire: number;
        earth: number;
    };
    rootGrade: RootGrade;
    talents: SpecializedTalents;
    proficiencies: Record<string, number>;
    combatProficiencies: Record<string, number>;
    tier: TalentTier;
    element: Element;
    status: 'healthy' | 'injured' | 'dead';
    loyalty: number; 
    assignment: TaskType;
    legacyPoints: number; 
    deathYear?: number;
    mainMethodId: number | null;
    movementMethodId: number | null;
    auxMethodIds: number[];
    equippedItems: {
        weapon: number | null;
        armor: number | null;
        accessory: number | null;
        treasure: number | null;
    };
    personalInventory: Inventory;
    cultivationProgress: number;
    developmentPlan: DevelopmentPlan;
    divineAbilities: string[];
    family: string;
    sect: string;
    position: string;
    fatherId?: string | null;
    motherId?: string | null;
    title?: string;
    spouseId?: string | null;
    mentorId?: string | null;
}

export interface MysticRealm {
    id: string;
    name: string;
    realmLimit: Realm; 
    startTime: number;
    duration: number; 
    regionId: string;
    participants: string[]; 
    competitors: Record<string, string[]>; 
}

export interface Region {
    id: string;
    name: string;
    description: string;
    difficulty: number;
    owner: FactionType;
    x: number;
    y: number;
    type: RegionType;
    category: RegionCategory;
    settlementType: SettlementType;
    isDiscovered: boolean;
    resources: string[];
    production?: {
        stones?: number;
        merit?: number;
        items?: Record<number, number>;
    };
    activeMission?: {
        memberId?: string;
        memberIds?: string[];
        turnsRemaining: number;
        totalTurns: number;
        type: string;
    };
    guardMemberId?: string; 
    controlValue?: number;
    occupancyStatus?: 'idle' | 'secured' | 'disputed';
}

export interface GameState {
    year: number;
    season: number;
    spiritStones: number;
    merit: number; 
    luck: number; 
    members: ClanMember[];
    regions: Region[];
    buildings: Building[];
    inventory: Inventory;
    currentRegionId: string;
    logs: string[];
    heritagePool: number;
    unlockedPositions: string[];
    flags: Record<string, any>;
    eventQueue: string[];
    factionReputation: Record<string, number>; 
    activeMysticRealms: MysticRealm[];
}
